module signal_generator
(
    input clk,
    input rst_n,
    output reg [4:0] wave
);

    reg [4:0] state;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= 5'd0;
            wave <= 5'd0;
        end
        else begin
            case (state)
                5'd0: begin
                    if (wave == 5'd31)
                        state <= 5'd1;
                    else
                        wave <= wave + 5'd1;
                end
                5'd1: begin
                    if (wave == 5'd0)
                        state <= 5'd0;
                    else
                        wave <= wave - 5'd1;
                end
                default: begin
                    state <= 5'd0;
                    wave <= 5'd0;
                end
            endcase
        end
    end

endmodule
